1	export interface ItemSpec {
2	  type: string;
3	}
4	
5	export interface Customer {
6	  yearsWithMHPCO: number;
7	}
8	
9	export interface QuoteInput {
10	  customer: Customer;
11	  items: ItemSpec[];
12	}
13	
14	export interface QuoteResult {
15	  premium: number;
16	}
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	};
25	
26	function basePremiumFor(item: ItemSpec): number {
27	  return BASE_PREMIUMS[item.type] ?? 0;
28	}
29	
30	export function quote(input: QuoteInput): QuoteResult {
31	  const policyBasePremium = input.items.reduce(
32	    (sum, item) => sum + basePremiumFor(item),
33	    0
34	  );
35	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
36	  return {
37	    premium: policyBasePremium + firstInsuranceSurcharge + PROCESSING_FEE,
38	  };
39	}
40	
41	export function claim(): unknown {
42	  return undefined;
43	}
